具体修复指令：
1. 第 1 行，修改导入：`import { db, _ } from '../db';`
2. 第 67-83 行，重写 updateInventory 函数为：
```typescript
export async function updateInventory(
  id: string,
  data: Partial<InventoryUpdatableFields>,
): Promise<void> {
  try {
    validateUpdateInventoryData(data);

    // 获取当前记录（含 version）
    const existingRes = await typedCollection<Inventory>(COLLECTIONS.INVENTORY).doc(id).get();
    const existing = existingRes.data as Inventory;
    if (!existing) {
      throw new Error(`Inventory 记录不存在: ${id}`);
    }

    const currentVersion = Number(existing.version) || 0;
    const updateRes = await typedCollection<Inventory>(COLLECTIONS.INVENTORY)
      .where({ _id: id, version: currentVersion })
      .update({
        data: {
          ...data,
          version: _.inc(1),
          updated_at: db.serverDate(),
        },
      });

    if ((updateRes.stats?.updated ?? 0) === 0) {
      throw new Error('乐观锁冲突：库存记录已被其他用户修改，请刷新后重试');
    }
  } catch (err: unknown) {
    logger.error('更新 inventory 失败', err, { service: 'inventoryMutation', operation: 'updateInventory' });
    throw err;
  }
}
```
